// searchKindIcon / searchKindLabel give each content kind a glyph + human label.
func searchKindIcon(kind string) string {
	switch kind {
	case "chat":
		return "💬"
	case "thread", "post":
		return "📋"
	case "issue", "issue_comment":
		return "🐞"
	case "discussion", "discussion_reply":
		return "🗣"
	case "project":
		return "📂"
	case "ai":
		return "🤖"
	}
	return "•"
}

func searchKindLabel(kind string) string {
	switch kind {
	case "chat":
		return "chat"
	case "thread":
		return "thread"
	case "post":
		return "reply"
	case "issue":
		return "issue"
	case "issue_comment":
		return "issue comment"
	case "discussion":
		return "discussion"
	case "discussion_reply":
		return "discussion reply"
	case "project":
		return "project"
	case "ai":
		return "agent thread"
	}
	return kind
}

// searchHighlight escapes the snippet, then turns the FTS5 «»-delimiters into
// <mark> so matched terms are highlighted without trusting raw content.
func searchHighlight(snippet string) string {
	s := html.EscapeString(snippet)
	s = strings.ReplaceAll(s, "«", "<mark>")
	s = strings.ReplaceAll(s, "»", "</mark>")
	return s
}

